int Q(int x, int y, int k) {
	cout << "? " << x << ' ' << y << ' ' << k << endl;
	cout.flush();
	int res; cin >> res;
	return res;
}
void A(int k) {
	cout << "! " << k << endl;
	cout.flush();
}
void solve(int CASE)
{
	int n, k; cin >> n >> k;
	var check = [&](int mid)->bool {
		int x = n, y = 1, sum = 0;
		while (x >= 1 and y <= n) {
			if (Q(x, y, mid)) {
				y++;
				sum += x;
			}
			else x--;
		}
		return sum >= n * n - k + 1;
		};
	int l = 1, r = n * n, ans = 0;
	while (l <= r) {
		int mid = l + r >> 1;
		if (check(mid)) {
			r = mid - 1;
			ans = mid;
		}
		else l = mid + 1;
	}
	A(ans);
	return;
}
